## 7.2 Project Linking Routes

### 7.2 Project Linking Routes

**File:** `apps/web/app/api/projects/[projectId]/shared-contexts/route.ts`

```typescript
import { NextResponse } from 'next/server'
import { z } from 'zod'
import { requireAuth } from '@/lib/auth/require-auth'
import { handleError } from '@/lib/errors'
import {
  getProjectSharedContexts,
  linkCollectionToProject,
  reorderProjectCollections,
} from '@/lib/db/queries/shared-collections'
import { detectConflicts } from '@/lib/services/internal-llm'
import { onProjectLinksChanged } from '@/lib/services/cache'

const linkSchema = z.object({
  collectionId: z.string(),
  priority: z.number().optional(),
  tokenBudgetPercent: z.number().min(1).max(100).optional(),
  enabledCategories: z.array(z.enum(['MANDATORY', 'BEST_PRACTICES', 'GUIDELINES', 'REFERENCE'])).optional(),
  acknowledgeConflicts: z.boolean().optional(),
})

export async function GET(
  request: Request,
  { params }: { params: { projectId: string } }
) {
  try {
    const user = await requireAuth()
    const contexts = await getProjectSharedContexts(params.projectId)

    return NextResponse.json({ success: true, data: contexts })
  } catch (error) {
    return handleError(error)
  }
}

export async function POST(
  request: Request,
  { params }: { params: { projectId: string } }
) {
  try {
    const user = await requireAuth()
    const body = linkSchema.parse(await request.json())

    // Check for conflicts before linking
    if (!body.acknowledgeConflicts) {
      const existingContexts = await getProjectSharedContexts(params.projectId)
      const existingDocs = existingContexts.flatMap(c =>
        c.collection.documents.map(d => ({ title: d.title, content: d.content }))
      )

      const newCollection = await getCollectionById(body.collectionId, user.id)
      if (!newCollection) {
        return NextResponse.json({ error: 'Collection not found' }, { status: 404 })
      }

      const newDocs = newCollection.documents.map(d => ({ title: d.title, content: d.content }))

      const conflicts = await detectConflicts(existingDocs, newDocs)

      if (conflicts.length > 0) {
        return NextResponse.json({
          success: false,
          conflicts,
          message: 'Conflicts detected. Set acknowledgeConflicts=true to proceed.'
        }, { status: 409 })
      }
    }

    const link = await linkCollectionToProject(
      params.projectId,
      body.collectionId,
      user.id,
      {
        priority: body.priority,
        tokenBudgetPercent: body.tokenBudgetPercent,
        enabledCategories: body.enabledCategories,
      }
    )

    // Invalidate caches
    await onProjectLinksChanged(params.projectId)

    return NextResponse.json({ success: true, data: link })
  } catch (error) {
    return handleError(error)
  }
}
```

